import{_ as t,o as e,c as i,ak as s}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"Navicat / SQLyog / DBeaver 工具使用","description":"","frontmatter":{},"headers":[],"relativePath":"mysql/basic/install/tools.md","filePath":"mysql/basic/install/tools.md","lastUpdated":1774248380000}'),l={name:"mysql/basic/install/tools.md"};function d(r,a,h,n,o,c){return e(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="navicat-sqlyog-dbeaver-工具使用" tabindex="-1">Navicat / SQLyog / DBeaver 工具使用 <a class="header-anchor" href="#navicat-sqlyog-dbeaver-工具使用" aria-label="Permalink to “Navicat / SQLyog / DBeaver 工具使用”">​</a></h1><h2 id="为什么需要图形化客户端" tabindex="-1">为什么需要图形化客户端 <a class="header-anchor" href="#为什么需要图形化客户端" aria-label="Permalink to “为什么需要图形化客户端”">​</a></h2><p>命令行能搞定一切，但图形化工具能让日常开发效率提升 10 倍：</p><ul><li>不用记 SQL 语法也能查看 / 修改数据</li><li>表结构一目了然，不用 <code>DESC table_name</code></li><li>快速执行 SQL 脚本，导出数据到 Excel</li><li>批量操作，定时任务</li></ul><p>三个工具各有特点，选一个最顺手的。</p><h2 id="navicat-premium-推荐" tabindex="-1">Navicat Premium（推荐） <a class="header-anchor" href="#navicat-premium-推荐" aria-label="Permalink to “Navicat Premium（推荐）”">​</a></h2><h3 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to “下载与安装”">​</a></h3><p>官网：<a href="https://www.navicat.com/en/products/navicat-premium" target="_blank" rel="noreferrer">https://www.navicat.com/en/products/navicat-premium</a></p><p>提供 14 天免费试用。Windows / macOS / Linux 都能装。</p><h3 id="连接-mysql" tabindex="-1">连接 MySQL <a class="header-anchor" href="#连接-mysql" aria-label="Permalink to “连接 MySQL”">​</a></h3><ol><li>点击左上角「<strong>连接</strong>」→「<strong>MySQL</strong>」</li><li>填写连接信息：</li></ol><table tabindex="0"><thead><tr><th>字段</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td>连接名</td><td>随便起，方便识别</td><td><code>本地 MySQL 8.0</code></td></tr><tr><td>主机</td><td>数据库服务器地址</td><td><code>localhost</code> 或 <code>127.0.0.1</code></td></tr><tr><td>端口</td><td>MySQL 端口</td><td><code>3306</code>（默认）</td></tr><tr><td>用户名</td><td>MySQL 用户名</td><td><code>root</code></td></tr><tr><td>密码</td><td>MySQL 密码</td><td><code>xxxxx</code></td></tr></tbody></table><ol start="3"><li>点击「测试连接」，成功后再点确定</li></ol><h3 id="常用功能" tabindex="-1">常用功能 <a class="header-anchor" href="#常用功能" aria-label="Permalink to “常用功能”">​</a></h3><h4 id="查询数据" tabindex="-1">查询数据 <a class="header-anchor" href="#查询数据" aria-label="Permalink to “查询数据”">​</a></h4><ol><li>双击连接 → 双击数据库 → 右键表 → 「打开表」或「设计表」</li><li>或者点击左上角「查询」→「新建查询」，写 SQL：</li></ol><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> status</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="导入-导出数据" tabindex="-1">导入 / 导出数据 <a class="header-anchor" href="#导入-导出数据" aria-label="Permalink to “导入 / 导出数据”">​</a></h4><ul><li><strong>导入</strong>：右键表 → 「导入向导」，支持 Excel、CSV、JSON、XML 等格式</li><li><strong>导出</strong>：右键表 → 「导出向导」，可导出 Excel、SQL 文件等</li></ul><h4 id="数据同步" tabindex="-1">数据同步 <a class="header-anchor" href="#数据同步" aria-label="Permalink to “数据同步”">​</a></h4><p>Tools → 「数据同步」，选择源和目标，一键同步表结构或数据。</p><h4 id="模型功能-er-图" tabindex="-1">模型功能（ER 图） <a class="header-anchor" href="#模型功能-er-图" aria-label="Permalink to “模型功能（ER 图）”">​</a></h4><p>Tools → 「逆向数据库」，选择表，自动生成 ER 图。</p><h3 id="navicat-快捷键" tabindex="-1">Navicat 快捷键 <a class="header-anchor" href="#navicat-快捷键" aria-label="Permalink to “Navicat 快捷键”">​</a></h3><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl + Q</code></td><td>新建查询</td></tr><tr><td><code>Ctrl + R</code></td><td>执行选中的 SQL</td></tr><tr><td><code>Ctrl + Shift + R</code></td><td>执行全部 SQL</td></tr><tr><td><code>Ctrl + D</code></td><td>快速查看表结构</td></tr><tr><td><code>Ctrl + L</code></td><td>删除当前行</td></tr><tr><td><code>Ctrl + ,</code></td><td>偏好设置</td></tr></tbody></table><h2 id="sqlyog-轻量级-推荐-windows" tabindex="-1">SQLyog（轻量级，推荐 Windows） <a class="header-anchor" href="#sqlyog-轻量级-推荐-windows" aria-label="Permalink to “SQLyog（轻量级，推荐 Windows）”">​</a></h2><h3 id="下载与安装-1" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装-1" aria-label="Permalink to “下载与安装”">​</a></h3><p>官网：<a href="https://www.webyog.com/product/sqlyog" target="_blank" rel="noreferrer">https://www.webyog.com/product/sqlyog</a></p><p>社区版免费，需要注册账号下载。Windows 专属。</p><h3 id="连接-mysql-1" tabindex="-1">连接 MySQL <a class="header-anchor" href="#连接-mysql-1" aria-label="Permalink to “连接 MySQL”">​</a></h3><ol><li>点击「新建」→ 填写连接信息（同 Navicat）</li><li>保存并连接</li></ol><h3 id="常用功能-1" tabindex="-1">常用功能 <a class="header-anchor" href="#常用功能-1" aria-label="Permalink to “常用功能”">​</a></h3><h4 id="数据库-表管理" tabindex="-1">数据库 / 表管理 <a class="header-anchor" href="#数据库-表管理" aria-label="Permalink to “数据库 / 表管理”">​</a></h4><p>左侧树形结构展示所有数据库和表。右键数据库：</p><ul><li>新建数据库</li><li>刷新</li><li>备份 / 恢复</li></ul><p>右键表：</p><ul><li>打开表（查看数据）</li><li>刷新表</li><li>优化表 / 检查表</li><li>导出结果集</li></ul><h4 id="sql-执行器" tabindex="-1">SQL 执行器 <a class="header-anchor" href="#sql-执行器" aria-label="Permalink to “SQL 执行器”">​</a></h4><p>写 SQL 后：</p><ul><li><code>F5</code>：执行全部</li><li><code>F9</code>：执行选中部分</li><li><code>Ctrl + Shift + R</code>：执行并格式化</li></ul><h4 id="快速架构同步" tabindex="-1">快速架构同步 <a class="header-anchor" href="#快速架构同步" aria-label="Permalink to “快速架构同步”">​</a></h4><p>右键数据库 → 「同步架构」，自动对比两个数据库的差异，生成 ALTER 语句。</p><h3 id="快捷键" tabindex="-1">快捷键 <a class="header-anchor" href="#快捷键" aria-label="Permalink to “快捷键”">​</a></h3><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>F5</code></td><td>执行 SQL</td></tr><tr><td><code>F8</code></td><td>格式化 SQL</td></tr><tr><td><code>Ctrl + Shift + T</code></td><td>创建表</td></tr><tr><td><code>Ctrl + 1/2/3</code></td><td>切换结果集格式</td></tr></tbody></table><h2 id="dbeaver-免费跨平台" tabindex="-1">DBeaver（免费跨平台） <a class="header-anchor" href="#dbeaver-免费跨平台" aria-label="Permalink to “DBeaver（免费跨平台）”">​</a></h2><h3 id="下载与安装-2" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装-2" aria-label="Permalink to “下载与安装”">​</a></h3><p>官网：<a href="https://dbeaver.io/download/" target="_blank" rel="noreferrer">https://dbeaver.io/download/</a></p><p>社区版免费，基于 Eclipse，支持 Windows / macOS / Linux。</p><h3 id="连接-mysql-2" tabindex="-1">连接 MySQL <a class="header-anchor" href="#连接-mysql-2" aria-label="Permalink to “连接 MySQL”">​</a></h3><ol><li>点击「数据库」→「新建连接」</li><li>选择 MySQL</li><li>填写主机、端口、数据库、用户名、密码</li><li>点击测试连接</li></ol><h3 id="常用功能-2" tabindex="-1">常用功能 <a class="header-anchor" href="#常用功能-2" aria-label="Permalink to “常用功能”">​</a></h3><h4 id="er-图" tabindex="-1">ER 图 <a class="header-anchor" href="#er-图" aria-label="Permalink to “ER 图”">​</a></h4><p>右键表 → 「查看关系图」→ 自动生成当前表的关联关系图。</p><h4 id="数据导出" tabindex="-1">数据导出 <a class="header-anchor" href="#数据导出" aria-label="Permalink to “数据导出”">​</a></h4><p>右键结果集 → 「导出数据」，支持 CSV、JSON、SQL INSERT、Excel 等格式。</p><h4 id="sql-编辑器" tabindex="-1">SQL 编辑器 <a class="header-anchor" href="#sql-编辑器" aria-label="Permalink to “SQL 编辑器”">​</a></h4><p>强大的 SQL 编辑器，支持代码补全、格式化、执行历史。</p><h4 id="导入数据" tabindex="-1">导入数据 <a class="header-anchor" href="#导入数据" aria-label="Permalink to “导入数据”">​</a></h4><p>右键表 → 「导入数据」，支持批量导入大文件。</p><h3 id="插件生态" tabindex="-1">插件生态 <a class="header-anchor" href="#插件生态" aria-label="Permalink to “插件生态”">​</a></h3><p>DBeaver 支持大量插件：</p><ul><li>数据可视化（图表）</li><li>数据库比较</li><li>数据迁移</li><li>MongoDB、Redis、PostgreSQL 等多数据库支持</li></ul><h3 id="快捷键-1" tabindex="-1">快捷键 <a class="header-anchor" href="#快捷键-1" aria-label="Permalink to “快捷键”">​</a></h3><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl + Enter</code></td><td>执行 SQL</td></tr><tr><td><code>Ctrl + Shift + F</code></td><td>格式化 SQL</td></tr><tr><td><code>Ctrl + /</code></td><td>注释 / 取消注释</td></tr><tr><td><code>Ctrl + Space</code></td><td>代码补全</td></tr></tbody></table><h2 id="三个工具对比" tabindex="-1">三个工具对比 <a class="header-anchor" href="#三个工具对比" aria-label="Permalink to “三个工具对比”">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>Navicat</th><th>SQLyog</th><th>DBeaver</th></tr></thead><tbody><tr><td>费用</td><td>付费（贵）</td><td>社区版免费</td><td>免费</td></tr><tr><td>平台</td><td>全平台</td><td>仅 Windows</td><td>全平台</td></tr><tr><td>界面</td><td>现代化</td><td>老派</td><td>Eclipse 风</td></tr><tr><td>性能</td><td>轻量快速</td><td>轻量快速</td><td>较重（功能多）</td></tr><tr><td>ER 图</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>数据同步</td><td>✅</td><td>✅（付费版）</td><td>✅</td></tr><tr><td>SQL 格式化</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>适合人群</td><td>愿意付费的专业 DBA</td><td>Windows 用户</td><td>跨平台 / 开源党</td></tr></tbody></table><h2 id="数据库连接字符串-代码中用" tabindex="-1">数据库连接字符串（代码中用） <a class="header-anchor" href="#数据库连接字符串-代码中用" aria-label="Permalink to “数据库连接字符串（代码中用）”">​</a></h2><p>安装完工具之后，你的数据库连接信息：</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># MySQL 8.0</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">host</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">localhost</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3306</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">database</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">school_db</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">username</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">root</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">password</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your_password</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># JDBC URL</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">jdbc:mysql://localhost:3306/school_db?useUnicode=true&amp;characterEncoding=utf8mb4&amp;useSSL=false&amp;serverTimezone=Asia/Shanghai</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to “下一步”">​</a></h2><p>客户端装好了，接下来了解 <a href="/database/mysql/basic/dir-structure">MySQL 目录结构</a>，搞清楚 MySQL 装好之后，各个文件都在哪里。</p>`,71)])])}const k=t(l,[["render",d]]);export{b as __pageData,k as default};
